chrome.runtime.onInstalled.addListener(()=>{console.log("Lector AI installed"),chrome.contextMenus.create({id:"summarize-selection",title:"Summarize with Lector AI",contexts:["selection"]}),chrome.contextMenus.create({id:"translate-selection",title:"Translate with Lector AI",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener((e,t)=>{e.menuItemId==="summarize-selection"&&e.selectionText&&chrome.runtime.sendMessage({action:"summarize",text:e.selectionText}),e.menuItemId==="translate-selection"&&e.selectionText&&chrome.runtime.sendMessage({action:"translate",text:e.selectionText})});chrome.runtime.onMessage.addListener((e,t,r)=>{if(e.action==="summarize")return n(e.text).then(r),!0;if(e.action==="translate")return o(e.text,e.targetLang).then(r),!0});async function n(e){try{return await(await fetch("https://your-app.vercel.app/api/summarize",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:e})})).json()}catch(t){return console.error("Summarize error:",t),{error:"Failed to summarize"}}}async function o(e,t="en"){try{return await(await fetch("https://your-app.vercel.app/api/translate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:e,targetLang:t})})).json()}catch(r){return console.error("Translate error:",r),{error:"Failed to translate"}}}
